package com.indianhive.web.Dishes.repository;import com.indianhive.web.Dishes.entity.dishEntity;import org.springframework.data.jpa.repository.JpaRepository;import org.springframework.stereotype.Repository;import java.util.List;import java.util.Optional;@Repositorypublic interface dishRepository extends JpaRepository<dishEntity, Long> {    Optional<dishEntity> findByName(String name);    List<dishEntity> findByIsAvailableTrue();    List<dishEntity> findBySpiceLevel(Integer spiceLevel);    List<dishEntity> findByPriceBetween(Double minPrice, Double maxPrice);    List<dishEntity> findByNameContainingIgnoreCase(String keyword);    List<dishEntity> findByDietaryInfoContaining(String dietaryInfo);    boolean existsByName(String name);}